const formLogin=document.getElementById("loginForm"),emailInput=document.getElementById("email"),passwordInput=document.getElementById("password"),passwordDiv=document.getElementById("div-password"),btnIcon=document.getElementById("btnIcon"),icon=document.getElementById("icon");let isVisible=!1;btnIcon.addEventListener("click",()=>{isVisible?(icon.classList.remove("fa-eye"),icon.classList.add("fa-eye-slash"),isVisible=!1,passwordInput.type="password"):(icon.classList.remove("fa-eye-slash"),icon.classList.add("fa-eye"),isVisible=!0,passwordInput.type="text")}),formLogin.addEventListener("submit",async function(e){e.preventDefault();const t={email:emailInput.value.trim(),password:passwordInput.value.trim()};try{const e=await fetch("../back/router.php?action=login",{method:"POST",credentials:"same-origin",headers:{"Content-Type":"application/json"},body:JSON.stringify(t)});(await e.json()).success?(showNotification("Connexion réussie","green"),setTimeout(()=>{window.location.href="../back/router.php?action=shop-view"},2e3)):showError(passwordDiv,"Identifiant ou mot de passe incorrect")}catch(e){console.error(e)}});